import { useRef } from 'react'
import { motion, useScroll, useTransform } from 'framer-motion'
import { ButtonLink } from '@/components/ui/button-link'
import { intro } from '@/content/site'

export default function Intro() {
  const ref = useRef<HTMLElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ['start end', 'end start'] })
  const y = useTransform(scrollYProgress, [0, 1], [40, -40])

  return (
    <section ref={ref} id="about" className="relative py-24 lg:py-32 bg-white overflow-hidden">
      <motion.div
        style={{ y }}
        className="absolute top-0 right-0 w-72 h-72 bg-blue-50 rounded-full blur-3xl opacity-60 -translate-y-1/2 translate-x-1/2 pointer-events-none"
      />

      <div className="relative max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <motion.h2
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.7 }}
          className="text-3xl sm:text-4xl font-bold text-slate-900 mb-8"
        >
          {intro.heading}
        </motion.h2>

        <div className="space-y-5">
          {intro.body.map((para, i) => (
            <motion.p
              key={i}
              initial={{ opacity: 0, y: 16 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: i * 0.1 }}
              className="text-lg text-slate-600 leading-relaxed"
            >
              {para}
            </motion.p>
          ))}
        </div>

        <motion.div
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.3 }}
          className="mt-10"
        >
          <ButtonLink href="#contact" size="lg" className="bg-blue-600 hover:bg-blue-700 text-white border-transparent">
            {intro.cta}
          </ButtonLink>
        </motion.div>
      </div>
    </section>
  )
}
